def list_hooks():
    """List all available hook templates."""
    print(f"\n{'='*60}")
    print("  Available Git Hook Templates")
    print(f"{'='*60}\n")

    for hook_type, templates in sorted(HOOK_TEMPLATES.items()):
        print(f"  \033[1m{hook_type}\033[0m")
        for name, tmpl in sorted(templates.items()):
            print(f"    - {name:20s} {tmpl['description']}")
        print()


def install_hook(repo_dir, hook_type, template_name, force=False):
    """Install a hook into a git repository."""
    hooks_dir = os.path.join(repo_dir, ".git", "hooks")

    if not os.path.isdir(os.path.join(repo_dir, ".git")):
        print(f"Error: '{repo_dir}' is not a git repository (no .git directory)")
        return False

    os.makedirs(hooks_dir, exist_ok=True)

    if hook_type not in HOOK_TEMPLATES:
        print(f"Error: Unknown hook type '{hook_type}'")
        print(f"Available: {', '.join(HOOK_TEMPLATES.keys())}")
        return False

    templates = HOOK_TEMPLATES[hook_type]
    if template_name not in templates:
        print(f"Error: Unknown template '{template_name}' for {hook_type}")
        print(f"Available: {', '.join(templates.keys())}")
        return False

    hook_path = os.path.join(hooks_dir, hook_type)

    if os.path.exists(hook_path) and not force:
        print(f"Warning: {hook_type} hook already exists at {hook_path}")
        print("Use --force to overwrite")
        return False

    content = templates[template_name]["content"]

    with open(hook_path, "w") as f:
        f.write(content)

    # Make executable
    st = os.stat(hook_path)
    os.chmod(hook_path, st.st_mode | stat.S_IEXEC | stat.S_IXGRP | stat.S_IXOTH)

    print(f"✓ Installed {hook_type}/{template_name} → {hook_path}")
    return True


def show_hook(hook_type, template_name):
    """Display a hook template without installing."""
    if hook_type not in HOOK_TEMPLATES:
        print(f"Error: Unknown hook type '{hook_type}'")
        return

    templates = HOOK_TEMPLATES[hook_type]
    if template_name not in templates:
        print(f"Error: Unknown template '{template_name}'")
        return

    tmpl = templates[template_name]
    print(f"\n# {hook_type}/{template_name}: {tmpl['description']}\n")
    print(tmpl["content"])


def status_hooks(repo_dir):
    """Show status of hooks in a repository."""
    hooks_dir = os.path.join(repo_dir, ".git", "hooks")

    if not os.path.isdir(hooks_dir):
        print("No .git/hooks directory found")
        return

    print(f"\n{'='*50}")
    print(f"  Git Hooks Status: {repo_dir}")
    print(f"{'='*50}\n")

    hook_names = ["pre-commit", "commit-msg", "pre-push", "post-merge",
                  "pre-rebase", "post-checkout", "post-commit", "prepare-commit-msg"]

    for name in hook_names:
        path = os.path.join(hooks_dir, name)
        if os.path.exists(path):
            is_exec = os.access(path, os.X_OK)
            is_sample = name.endswith(".sample")
            status = "\033[92m✓ active\033[0m" if is_exec and not is_sample else "\033[93m⚠ not executable\033[0m"
            size = os.path.getsize(path)
            print(f"  {status}  {name:25s} ({size} bytes)")
        else:
            sample = os.path.join(hooks_dir, f"{name}.sample")
            if os.path.exists(sample):
                print(f"  \033[90m- sample\033[0m  {name:25s} (sample only)")
            else:
                print(f"  \033[90m-\033[0m        {name}")

    print()


def remove_hook(repo_dir, hook_type):
    """Remove an installed hook."""
    hook_path = os.path.join(repo_dir, ".git", "hooks", hook_type)
    if os.path.exists(hook_path):
        os.remove(hook_path)
        print(f"✓ Removed {hook_type} hook")
        return True
    else:
        print(f"No {hook_type} hook found")
        return False


def main():
    parser = argparse.ArgumentParser(
        description="Git hooks generator — install, manage, and list pre-built hook templates",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  %(prog)s list                                      List all templates
  %(prog)s install pre-commit lint-staged             Install lint-staged hook
  %(prog)s install commit-msg conventional            Enforce conventional commits
  %(prog)s install pre-push run-tests --repo /path    Install in specific repo
  %(prog)s show pre-commit no-debug                   Preview a template
  %(prog)s status                                     Show installed hooks
  %(prog)s remove pre-commit                          Remove a hook
        """,
    )

    sub = parser.add_subparsers(dest="command", help="Command")

    # list
    sub.add_parser("list", help="List all available hook templates")

    # install
    install_p = sub.add_parser("install", help="Install a hook template")
    install_p.add_argument("hook_type", help="Hook type (e.g., pre-commit, commit-msg)")
    install_p.add_argument("template", help="Template name (e.g., lint-staged, conventional)")
    install_p.add_argument("--repo", default=".", help="Repository path (default: .)")
    install_p.add_argument("--force", action="store_true", help="Overwrite existing hook")

    # show
    show_p = sub.add_parser("show", help="Preview a hook template")
    show_p.add_argument("hook_type", help="Hook type")
    show_p.add_argument("template", help="Template name")

    # status
    status_p = sub.add_parser("status", help="Show hook status for a repo")
    status_p.add_argument("--repo", default=".", help="Repository path (default: .)")

    # remove
    remove_p = sub.add_parser("remove", help="Remove an installed hook")
    remove_p.add_argument("hook_type", help="Hook type to remove")
    remove_p.add_argument("--repo", default=".", help="Repository path (default: .)")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(0)

    if args.command == "list":
        list_hooks()
    elif args.command == "install":
        success = install_hook(args.repo, args.hook_type, args.template, force=args.force)
        sys.exit(0 if success else 1)
    elif args.command == "show":
        show_hook(args.hook_type, args.template)
    elif args.command == "status":
        status_hooks(args.repo)
    elif args.command == "remove":
        success = remove_hook(args.repo, args.hook_type)
        sys.exit(0 if success else 1)


if __name__ == "__main__":
    main()
